class RecencyIndex {
  final List<String> _keys = <String>[];

  void record(String key) {
    if (!_keys.contains(key)) _keys.add(key);
  }

  String? removeOldest() => _keys.isEmpty ? null : _keys.removeAt(0);

  List<String> get keys => List<String>.unmodifiable(_keys);
}

