import '../lib/asset.dart';
import '../lib/asset_cache.dart';
import '../lib/recency_index.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final index = RecencyIndex()..record('a')..record('b');
  check(index.removeOldest() == 'a', 'insertion order eviction');

  final cache = AssetCache(2);
  final a = Asset('1', <int>[1]);
  cache.put('a', a);
  cache.put('b', Asset('1', <int>[2]));
  cache.put('c', Asset('1', <int>[3]));
  check(cache.get('a') == null, 'oldest insertion evicted');
  check(cache.get('b') != null && cache.get('c') != null, 'new entries retained');
  print('public tests passed');
}
